B.Kp=new A.aW("arabulucu_06",B.cM,"Dava \u015fart\u0131 arabuluculukta arabulucu, ba\u015fvuru tarihinden itibaren s\xfcreci kural olarak ne kadar s\xfcrede tamamlamal\u0131d\u0131r?",B.FJ,0,"\u0130\u015f ve ticari uyu\u015fmazl\u0131klarda arabulucu, g\xf6revlendirildi\u011fi tarihten itibaren s\xfcreci \xfc\xe7 hafta i\xe7inde sonu\xe7land\u0131r\u0131r; bu s\xfcre zorunlu h\xe2llerde arabulucu taraf\u0131ndan en fazla bir hafta uzat\u0131labilir.")
