B.Kr=new A.aW("ispat_12",B.aX,"A\u015fa\u011f\u0131dakilerden hangisi, senetle ispat zorunlulu\u011fu olan bir hukuki i\u015flemin miktar ne olursa olsun tan\u0131kla ispat edilebilece\u011fi istisnai hallerden (delil ba\u015flang\u0131c\u0131 aranmaks\u0131z\u0131n) biri de\u011fildir?",B.DB,2,"HMK m. 203 uyar\u0131nca altsoy-\xfcstsoy, karde\u015fler ve e\u015fler aras\u0131ndaki i\u015flemlerde miktar ne olursa olsun tan\u0131k dinlenebilir. Ortaklar aras\u0131ndaki i\u015flemler kural olarak bu istisnaya dahil edilmemi\u015ftir.")
B.iw=s(["1 hafta","2 hafta","3 hafta","4 hafta"],t.s)
B.JS=new A.aW("ispat_13",B.aX,"Taraflar, bilirki\u015fi raporunun kendilerine tebli\u011f tarihinden itibaren kural olarak ka\xe7 hafta i\xe7inde raporda eksik g\xf6rd\xfckleri hususlar\u0131n bilirki\u015fiye tamamlatt\u0131r\u0131lmas\u0131n\u0131 mahkemeden isteyebilirler?",B.iw,1,"HMK m. 281/1 uyar\u0131nca taraflar, bilirki\u015fi raporunun tebli\u011fi tarihinden itibaren iki hafta i\xe7inde raporda eksik veya belirsiz g\xf6rd\xfckleri hususlar\u0131n giderilmesini yahut yeni bir bilirki\u015fi atanmas\u0131n\u0131 isteyebilirler.")
B.K4=new A.aW("gecici_08",B.bD,"Kar\u015f\u0131 taraf dinlenmeden (yoklu\u011funda) verilen ihtiyati tedbir kararlar\u0131na kar\u015f\u0131, itiraz hakk\u0131 olanlar karar\u0131n uygulanmas\u0131 s\u0131ras\u0131nda haz\u0131r bulunmuyorlarsa, tedbirin uygulanmas\u0131na ili\u015fkin tutana\u011f\u0131n tebli\u011finden itibaren en ge\xe7 ne kadar s\xfcre i\xe7inde itiraz edebilirler?",B.iw,0,"HMK m. 394/2 uyar\u0131nca kar\u015f\u0131 taraf dinlenmeden verilmi\u015f olan ihtiyati tedbir kararlar\u0131na itiraz s\xfcresi, karar\u0131n uyguland\u0131\u011f\u0131na ili\u015fkin tutana\u011f\u0131n tebli\u011finden itibaren bir haftad\u0131r.")
B.F5=s(["\u0130htiyati tedbir","\u0130htiyati haciz","Delil tespiti","\u0130htiyari dava arkada\u015fl\u0131\u011f\u0131"],t.s)
B.Ki=new A.aW("gecici_09",B.bD,"G\xf6r\xfclmekte olan veya ileride a\xe7\u0131lacak bir davada ispat vas\u0131tas\u0131 olarak kullan\u0131lacak olan delillerin kaybolmas\u0131 veya g\xf6sterilmesinin \xe7ok zorla\u015fmas\u0131 ihtimali kar\u015f\u0131s\u0131nda ba\u015fvurulan ge\xe7ici hukuki koruma kurumu a\u015fa\u011f\u0131dakilerden hangisidir?",B.F5,2,"HMK m. 400 uyar\u0131nca, taraflar hen\xfcz inceleme s\u0131ras\u0131 gelmemi\u015f olan veya ileride a\xe7\u0131lacak davada ileri s\xfcr\xfclecek delillerin kaybolaca\u011f\u0131 veya ileri s\xfcr\xfclmesinin zorla\u015faca\u011f\u0131 ihtimali varsa delil tespiti isteyebilir.")
B.K7=new A.aW("kanun_08",B.bF,"Hukuk mahkemeleri taraf\u0131ndan verilen nihai kararlara kar\u015f\u0131, karar\u0131n usul\xfcne uygun tebli\u011finden itibaren kural olarak ka\xe7 hafta i\xe7inde istinaf yoluna ba\u015fvurulabilir?",B.iw,1,"HMK m. 345 uyar\u0131nca istinaf yoluna ba\u015fvuru s\xfcresi, karar\u0131n usul\xfcne uygun olarak taraflara tebli\u011finden itibaren iki haftad\u0131r.")
B.FU=s(["Miktar veya de\u011feri temyiz s\u0131n\u0131r\u0131n\u0131 a\u015fan alacak davalar\u0131","Soyba\u011f\u0131na ili\u015fkin kararlar","\xc7eki\u015fmesiz yarg\u0131 i\u015flerinde verilen kararlar","Ta\u015f\u0131nmaz \xfczerindeki ayni haklara ili\u015fkin kararlar"],t.s)
B.Km=new A.aW("kanun_09",B.bF,"B\xf6lge adliye mahkemesi hukuk dairelerinden verilen a\u015fa\u011f\u0131daki kararlardan hangisine kar\u015f\u0131 kural olarak temyiz yoluna ba\u015fvurulamaz?",B.FU,2,"HMK m. 362/1-\xe7 bendine g\xf6re \xe7eki\u015fmesiz yarg\u0131 i\u015flerinde verilen b\xf6lge adliye mahkemesi kararlar\u0131 kesin olup bu kararlara kar\u015f\u0131 temyiz yoluna ba\u015fvurulamaz.")
B.Fb=s(["Feragat, h\xfck\xfcm kesinle\u015finceye kadar her zaman yap\u0131labilir.","Feragatin ge\xe7erlili\u011fi kar\u015f\u0131 taraf\u0131n veya mahkemenin kabul\xfcne ba\u011fl\u0131d\u0131r.","Feragat, kesin h\xfck\xfcm gibi hukuki sonu\xe7 do\u011furur.","\u015earta ba\u011fl\u0131 feragat kural olarak ge\xe7erli de\u011fildir."],t.s)
B.JY=new A.aW("taraf_08",B.bE,'Davac\u0131n\u0131n talep sonucundan k\u0131smen veya tamamen vazge\xe7mesi olan "feragat" kurumu ile ilgili a\u015fa\u011f\u0131dakilerden hangisi yanl\u0131\u015ft\u0131r?',B.Fb,1,"HMK m. 309 uyar\u0131nca feragat ve kabul, kar\u015f\u0131 taraf\u0131n veya mahkemenin muvafakatine ba\u011fl\u0131 de\u011fildir; tek tarafl\u0131 irade beyan\u0131yla derhal sonu\xe7 do\u011furur.")
B.AG=new A.H(1,0.8941176470588236,0.6039215686274509,0.8235294117647058,B.h)
B.JR=new A.l6("H\xfck\xfcm ve Kesin H\xfck\xfcm",B.AG,5,"hukumKesinHuku")
B.Dt=s(["Sadece taraflar\u0131n\u0131n","Sadece dava sebeplerinin","Taraflar\u0131n\u0131n, dava sebeplerinin ve ilk davan\u0131n h\xfck\xfcm f\u0131kras\u0131 ile ikinci davan\u0131n talep sonucunun","Sadece mahkemelerinin"],t.s)
B.Kv=new A.aW("hukum_01",B.JR,"Bir davada verilen karar\u0131n ba\u015fka bir davada maddi anlamda kesin h\xfck\xfcm te\u015fkil edebilmesi i\xe7in her iki davan\u0131n hangi unsurlar\u0131n\u0131n ayn\u0131 olmas\u0131 zorunludur?",B.Dt,2,"HMK m. 303/1 uyar\u0131nca maddi anlamda kesin h\xfck\xfcmden s\xf6z edilebilmesi i\xe7in her iki davan\u0131n taraflar\u0131n\u0131n, dava sebeplerinin (vak\u0131alar\u0131n) ve ilk davan\u0131n h\xfck\xfcm f\u0131kras\u0131 ile ikinci davan\u0131n talep sonucunun ayn\u0131 olmas\u0131 gerekir.")
B.Dw=s(["Eksikli\u011fi gidermesi i\xe7in davac\u0131ya bir haftal\u0131k kesin s\xfcre verir.","Davay\u0131 esastan reddeder.","Davay\u0131, dava \u015fart\u0131 yoklu\u011fu sebebiyle usulden reddeder.","Davay\u0131 durdurur ve taraflar\u0131 arabulucuya g\xf6nderir."],t.s)
B.JV=new A.aW("arabulucu_07",B.cM,"Kanunlarda arabuluculu\u011fa ba\u015fvurulmu\u015f olmas\u0131n\u0131n dava \u015fart\u0131 olarak \xf6ng\xf6r\xfcld\xfc\u011f\xfc durumlarda, davac\u0131 arabulucuya ba\u015fvurmadan do\u011frudan dava a\xe7arsa mahkeme nas\u0131l bir karar verir?",B.Dw,2,"6325 say\u0131l\u0131 Hukuk Uyu\u015fmazl\u0131klar\u0131nda Arabuluculuk Kanunu m. 18/A-2 uyar\u0131nca, arabulucuya ba\u015fvurulmadan dava a\xe7\u0131ld\u0131\u011f\u0131n\u0131n anla\u015f\u0131lmas\u0131 halinde herhangi bir i\u015flem yap\u0131lmaks\u0131z\u0131n davan\u0131n, dava \u015fart\u0131 yoklu\u011fu sebebiyle usulden reddine karar verilir.")
